class Solution:
    def smallestSubsequence(self, s: str) -> str:
        stack = []
        seen = set()
        for char in s:
            while stack and char < stack[-1] and len(seen) + (s.count(stack[-1]) - 1) >= len(set(s)):
                seen.remove(stack.pop())
            if char not in seen:
                stack.append(char)
                seen.add(char)
        return ''.join(stack)
